VALUES
  ('cpa-moex-01126', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，企業合併所產生商譽之金額為何？', '["$79,000", "$124,000", "$164,000", "$336,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01127', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日發行面額$10、市價$20之普通股25,000股取得乙公司全部淨資產，並支付 合併相關直接成本$30,000。此外，甲公司允諾若乙公司X1年稅前淨利能達到$750,000，則將額外發 行 10,000 股普通股給乙公司之股東。X1 年初該項或有對價之公允價值為$40,000，甲公司收購乙公 司之分錄應借記「投資乙公司」之金額為何？', '["$570,000", "$540,000", "$530,000", "$500,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01128', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X3年6月8日甲公司以現金$25,000、發行股票12,000股（每股面額$10、市價$56），收購乙公司 80%股權，當時乙公司可辨認資產之帳面金額為$560,000（公允價值$700,000）、負債之帳面金額為 $230,000（公允價值$230,000）。假設乙公司收購日之非控制權益係依公允價值衡量，且其收購日之 公允價值為$162,500，則收購日歸屬於非控制權益之商譽金額為何？', '["$0", "$68,500", "$80,250", "$376,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01129', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年底以$150,000的價格出售機器予其持股80%的乙公司。該機器成本為$200,000，出售 時帳面金額為$120,000，且該機器尚有5年的耐用年限，採直線法提列折舊。此一公司間銷售對X1年 的合併淨資產及合併淨利之影響為何？', '["合併淨資產增加$30,000，合併淨利增加$30,000", "合併淨資產增加$30,000，合併淨利減少$30,000", "合併淨資產減少$30,000，合併淨利減少$30,000", "均無影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01130', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X6年5月31日甲公司吸收合併乙公司，並委託一鑑價公司針對乙公司之建築物進行評價。該評價 作業於X6年底尚未完成，故甲公司暫以$420,000認列該項建築物，並估計其耐用年限自合併日起尚 有7年無殘值，採直線法提列折舊。該鑑價公司在X7年2月1日提出鑑價報告，指出此建築物於收 購日之公允價值估計為$576,000，耐用年限自收購日起尚有8年，其餘條件不變。甲公司在X7年2月 1日收到鑑價報告後，針對X6年財務報表中建築物帳面金額應追溯調整之金額為何？', '["$7,000", "$149,000", "$156,000", "$534,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01131', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年初以現金$360,000取得乙公司60%的股權，並依非控制權益公允價值$240,000衡量 非控制權益，當時乙公司可辨認淨資產的帳面金額與公允價值皆為$600,000。X1 年間，乙公司將成 本$600,000的商品以$800,000出售予甲公司，而甲公司截至X1年年底尚有$200,000的存貨未出售。 X1年，甲公司與乙公司的個別淨利（不含投資收益或股利收入）分別為$300,000與$150,000。X2年 間，乙公司將成本$900,000的商品以$1,200,000出售予甲公司，而甲公司截至X2年年底尚有$400,000 未出售。X2年，甲公司與乙公司的個別淨利（不含投資收益或股利收入）分別為$400,000與$250,000。 X1年至X2年間，甲公司和乙公司均無發放股利。試求X2年底甲公司帳上投資乙公司餘額為何？', '["$360,000", "$500,000", "$540,000", "$600,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01132', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X5年1月1日以$40,000取得乙公司80%股權而對乙公司取得控制，並依可辨認淨資產公 允價值之比例份額衡量非控制權益。當日乙公司之權益包括股本$30,000及保留盈餘$12,500。除存貨 價值低估$2,500 外，其他可辨認資產、負債之帳面金額均等於公允價值。假設甲公司適用之所得稅 率為25%，乙公司適用之稅率為20%。試問收購日工作底稿之沖銷分錄應認列之商譽為若干？', '["$4,000", "$4,125", "$4,400", "$4,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01133', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日持有乙公司80%股權，該日權益法下甲公司帳列「投資乙公司」帳戶餘額為 $450,000，且於該日無未攤銷差額。乙公司於同日持有甲公司10%股權，且採成本法處理其對甲公司 之投資。甲公司與乙公司於X2年之個別淨利（不含投資收益或股利收入）分別為$100,000與$50,000， 分別發放現金股利$50,000與$20,000。甲公司於X1年10月1日將成本$14,000之存貨以$20,000售予 乙公司。截至X1年底，乙公司購自甲公司該批存貨仍有1/3尚未出售。試問若採庫藏股票法，X1年 甲公司帳列「投資收益」為何？', '["$37,000", "$37,400", "$42,000", "$44,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01134', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1 年初臺北公司以$500,000 取得臺中公司 80%股權，採權益法處理該投資，當日臺中公司之權益 $500,000，且除房屋低估外，其餘資產及負債之公允價值均等於帳面金額，該房屋尚可使用二十年， 採用直線法折舊。X4年7月1日臺北公司出售部分投資而使其對臺中公司持股比率降至60%。臺中 公司X4年淨利為$62,000，係一年內平均賺得，X4年合併綜合損益表中，非控制權益淨利為何？', '["$10,000", "$12,400", "$16,725", "$43,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01135', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X2年1月1日購入乙公司80%股權而對乙公司取得控制，當時乙公司各項資產、負債帳面 金額均等於公允價值，且無合併商譽。乙公司於X2年底每股淨值為$8，X3年1月1日乙公司增資 發行新股 30,000 股，每股發行價格$12，甲公司全數認購後股權增加為 87.5%。甲公司投資帳戶於 X3年1月1日增加金額為何？', '["增加$240,000", "增加$345,000", "增加$351,000", "增加$360,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01136', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X6年1月1日以$1,200,000取得乙公司90%股權。當時乙公司可辨認資產、負債之公允價 值與其帳面金額相等，乙公司權益如下： 特別股股本，面額$100、優先股利率6%，累積非參加，收回價格$120  $300,000 普通股股本，面額$10  500,000 資本公積－普通股  200,000 保留盈餘     500,000 權益總額  $1,500,000 甲公司採權益法處理該項投資，並依收購日公允價值$340,000與$116,000衡量屬非控制權益之特別 股與普通股。乙公司特別股無積欠股利，X6年1月1日合併資產負債表上之商譽金額為若干？', '["$4,000", "$50,000", "$156,000", "$176,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01137', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日以股份交換方式吸收合併乙公司，合併後甲公司流通在外普通股股數為 100,000股，且於X1年上半年度維持不變。乙公司於合併後成為甲公司轄下之事業單位。依該合併 契約，若於合併後第一年之年度結算後，原乙公司所屬事業單位全年度之部門營業利益率達 15%以 上，甲公司須額外發行新股20,000股予乙公司原股東。此外，甲公司基於留才，於收購日發行25,000 單位認股權給與乙公司研發人員，每單位認股權可按$40認購甲公司普通股一股，於合併日二年後既 得。甲公司X1年上半年度之淨利為$500,000，原乙公司事業單位上半年度之部門營業利益率為18%。 甲公司普通股於X1年上半年之平均股價為$50。試問甲公司X1年上半年度之合併綜合損益表上稀 釋每股盈餘為何？', '["$3.45", "$4.00", "$4.17", "$4.76"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01138', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '臺北公司於X1年1月1日取得臺中公司60%的股權。該日臺中公司亦取得臺南公司70%的股權。 假設臺北公司與臺中公司移轉對價超過所取得可辨認淨資產帳面金額皆歸因於商譽。X1年三家公司 （未含投資收益或股利收入之個別淨利）分別為臺北公司$500,000、臺中公司$300,000以及臺南公司 $400,000。則X1年控制權益淨利為何？', '["$808,000", "$848,000", "$920,000", "$960,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01139', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日借入美元$20,000，借款期間為二年，利率5%，每年付息一次。甲公司以新 臺幣為功能性貨幣，X1年1月1日、12月31日及全年平均匯率分別為31.7、32.2及32.0，甲公司 X1年度應認列之兌換（損）益金額為何？', '["$(200)", "$(9,800)", "$(10,000)", "$(10,200)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01140', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年12月31日取得B公司100%股權，B公司記帳貨幣為美元，功能性貨幣為新臺幣， 甲公司之表達貨幣為新臺幣。B公司之X2年綜合損益表資料如下： 銷貨收入  US$100,000 銷貨成本  50,000 折舊費用  10,000 其他營業費用  20,000 ⑴不動產、廠房與設備購入時之匯率為30.0，採歷史成本衡量。 ⑵存貨採先進先出法，期初存貨美元$10,000為X1年底購入，X2年進貨全年平均發生，期末存貨成 本為美元$10,000，淨變現價值為美元$9,900。 ⑶X1年財務報表由美元換算為新臺幣之兌換差額為新臺幣$250,000（借餘）。 ⑷X2年匯率並無劇烈波動，相關日美元對新臺幣之直接匯率：1月1日（X1年12/31）：30.5；12 月31日：31.5；X2年全年平均匯率為31.0。美元與新臺幣皆非為高度通貨膨脹經濟之下貨幣。 X2年B公司換算為新臺幣之綜合損益表之本期淨利為何？', '["$370,000", "$385,000", "$620,000", "$635,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01141', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '下列何種狀況下的嵌入式衍生工具與主契約之經濟特性及風險係緊密關聯？', '["嵌入於債務工具之賣權，使持有人可要求發行人按某一商品價格之變動所決定之價格，以現金再 買回該主債務工具", "發行具利率上限之浮動利率公司債時，市場利率為6%，該債券之利率上限為8%", "丙公司向馬來西亞採購原油時，簽定之以日幣計價原油購買合約，其所嵌入之外幣衍生工具。假 設馬來西亞當地交易慣用貨幣為馬來西亞幣；且原油合約之慣用貨幣為美元", "甲公司持有乙公司之可買回特別股，乙公司可以特定價格再買回該特別股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01142', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '某公司在全國各地有多個分公司，分公司的商品一律由總公司配送，移轉價格為總公司進貨成本加 價。X1年5月1日總公司將基隆分公司訂貨的商品運往宜蘭分公司，並支付$2,200的運費，總公司 此批商品的進貨成本為$16,000。X1年5月2日宜蘭分公司緊急將此批商品運往基隆分公司，並支付 $900 的運費。正常情況下，總公司運往基隆分公司的商品運費為$1,500，宜蘭分公司運往基隆分公司 商品運費為$800，總公司對該批商品配送於帳上借記「基隆分公司往來」$21,500，試問總公司之 移轉價格為成本加價多少%？', '["15%", "25%", "20%", "18%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01143', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '陳小姐為知名律師，1小時鐘點費$10,000，可視情況打九折。X1年5月20日甲慈善基金會舉辦募款 義賣活動，陳小姐律師自願無償從事義賣場清潔活動，耗時5小時。則甲慈善基金會應認列之「勞務 捐贈」金額為何？', '["$0", "$10,000", "$45,000", "$50,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01144', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年12月1日與英國乙公司簽訂定價300,000英鎊不可取消之進貨合約，乙公司並於X2年 1月31日交貨。甲公司為規避前述進貨合約之匯率風險，甲公司並於X1年12月1日簽訂X2年1月', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01145', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '日到期之零成本且現金淨額交割之遠期外匯合約，約定之遠期匯率為$47.425，金額為 300,000 英鎊，且指定該遠匯合約之即期匯率部分為避險工具。若甲公司對外幣確定承諾之匯率避險係以現 金流量避險處理，且估計遠匯合約公允價值時之折現率為年利率6%。相關匯率資料如下：（計算結 果四捨五入至整數位） X1/12/01  X1/12/31  X2/01/31 英鎊即期匯率  $47.000  $47.370  $47.390 30天英鎊遠期匯率  $47.180  $47.515  $47.650 60天英鎊遠期匯率  $47.425  $47.750  $46.825 有關前述避險及後續進貨合約之會計處理，以下敘述何者正確？', '["甲公司為規避進貨合約之匯率變動風險，簽訂之遠期外匯合約為做多合約", "X1年12月31日甲公司認列避險工具資產之金額為$26,866", "X1年12月31日甲公司認列「避險工具損益」為貸方金額$110,448", "X1年12月31日甲公司認列「金融工具評價損益」為借方金額$83,582 X1年12月31日甲公司認列「其他綜合損益－現金流量避險」為貸方金額$26,866"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01146', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '下列何者應列為其他綜合損益？', '["現金流量避險之下，避險工具之利益或損失屬於有效避險之部分", "於國外營運機構之個別財務報表上，構成報導個體對國外營運機構淨投資一部分之貨幣性項目， 所產生之兌換差額", "於報導個體之單獨財務報表中，構成報導個體對國外營運機構淨投資一部分之貨幣性項目，所產 生之兌換差額", "在包含國外營運機構及報導個體之合併財務報表中，構成報導個體對國外營運機構淨投資一部分 之貨幣性項目，所產生之兌換差額 公允價值避險之下，避險工具按公允價值再衡量所產生之利益或損失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01147', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '下列有關母公司額外購入子公司流通在外股份之敘述，何者正確？', '["合併綜合損益表上不需就此交易認列損益", "合併資產負債表上歸屬於母公司股東之權益增加", "合併資產負債表上非控制權益之金額減少", "合併商譽可能因此交易而增加，但不會減少 合併報表中併自子公司可辨認資產及負債之帳面金額於購入前後均相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01148', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日與乙公司簽訂技術授權合約，授權乙公司使用甲公司之某項技術，合約期限 為10年，不得展延。甲公司於X5年1月1日以現金$800,000吸收合併乙公司。當日乙公司可辨認 淨資產之公允價值分別為：與甲公司所簽訂之技術授權合約$90,000、其他可辨認資產$1,180,000 及 負債$640,000。該技術授權之合約條件對甲公司而言較市場條件不利，不利之金額為$30,000。合約 規定任一方欲提前解約時，須支付他方$20,000解約金，且甲公司於收購日前並未針對此不利狀況認 列任何資產或負債。下列有關甲公司X5年1月1日之會計處理，何者正確？', '["應認列「再取回之權利－技術授權」$90,000", "應認列技術授權合約結清損失$20,000", "企業合併之移轉對價為$800,000", "應認列之合併商譽為$150,000 應認列或有負債$10,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "aa44ee264bcd", "answer_pdf_sha1": "7ec3e9d3f436", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "高等會計學", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01149', 'cpa', 'cpa-moex-104-78566e18', 'sub-cpa-01', NULL, 'essay', '甲國際飯店係一家知名的連鎖飯店，鑑於顧客常常必須搭機洽公或旅遊，於X3年
年初參加乙航空公司所舉辦的「顧客忠誠旅程酬賓計畫」，凡顧客向飯店住房
或餐廳消費每滿$1,000，公司即贈予乙航空公司 1 哩的飛行哩數，累積一定哩
數後顧客可向乙航空公司兌換免費機票或升等座艙。其他相關資料如下：
(a)兩公司規定，給予顧客哩程數的計算，係以甲國際飯店所開立的發票金額為
準，甲國際飯店估計每一哩飛行哩數的公允價值為$50，每贈送顧客一哩的
飛行哩數應支付乙航空公司$45。
(b)由於酬賓計畫屢獲顧客好評，甲國際飯店決定於 X4 年擴大實施，為使顧客
有多樣性選擇，飯店決定自己主辦該活動，除前述哩程兌換辦法外，亦推出
積點兌換住房及免費餐券辦法。凡顧客向飯店住房或餐廳消費每滿$1,000可
累積1點，每積滿20點可兌換住房券一張，或可選擇每積滿10點兌換免費
餐券一張。甲國際飯店估計每一積點的公允價值$100，每張住房券成本為
$2,400，每張免費餐券成本為$800。顧客在消費時，即須選擇參加哩程兌換
辦法或積點兌換辦法。
試作下列兩種情況有關「酬賓計畫」之分錄：
若甲國際飯店係代理乙航空公司運作該計畫，X3年度甲國際飯店共開立發票
$9,000,000。（5分）
若甲國際飯店係自行運作該計畫，X4 年度甲國際飯店共開立發票
$15,000,000，其中有2/5選擇哩程兌換辦法，3/5選擇積點兌換辦法。飯店估
計積點兌換辦法約有90%會提出兌換，X4年度共兌換住房券的點數有4,000
